nta.declaration:
// ============================================================
// GLOBAL DECLARATIONS
// ============================================================

// Communication channels
// Regular channels (binary synchronization: sender waits for receiver)
chan follower_ready;       // Follower signals: I am in following position
chan leader_start;         // Leader signals: begin exploration
chan dead_end_alert;       // Leader signals: dead end detected, back up
chan follower_backed_up;   // Follower signals: backed up, you can reverse
chan reversal_done;        // Leader signals: reversal complete, resume
chan leader_lost_signal;   // Follower signals: I lost contact with leader
chan leader_found_reply;   // Leader signals: I am at this position

// Broadcast channels (sender does not wait; all enabled receivers sync)
broadcast chan emergency_stop;  // Emergency halt all robots

// ============================================================
// SHARED ABSTRACT STATE (simplified for model checking)
// ============================================================

// Abstract distance between robots (discretized):
//   0 = CLOSE   (≤ 0.7m, follower in following zone)
//   1 = MEDIUM  (0.7m - 1.5m, acceptable gap)
//   2 = FAR     (> 1.5m, leader should wait)
//   3 = LOST    (signal lost, > 5s timeout)
int[0,3] follower_distance;

// Leader path status:
//   0 = CLEAR      (can navigate forward)
//   1 = DEAD_END   (blocked, needs to reverse)
int[0,1] leader_path_status;

// Coordination flags
bool follower_is_searching;    // true when follower is in SEARCHING state
bool leader_is_waiting;        // true when leader is waiting for follower

// State sync counter (for liveness analysis)
int[0,10] sync_count;

template.declaration:
// Leader-local clock: reset on each state transition
clock t;

// Number of consecutive dead ends encountered (for liveness)
int[0,5] dead_end_count;

// Follower-local clock: reset on each state transition
clock t;

// Distance backed up during BACKING_UP state (abstract: 0=none, 1=enough)
int[0,1] backed_up_enough;

// Environment models external non-deterministic events:
//   - Obstacles that create dead ends for the leader
//   - Signal loss between robots (follower loses leader)
//   - Distance changes between robots
clock t_env;

nta.system:
// ============================================================
// SYSTEM COMPOSITION
// ============================================================
// Instantiate all three templates and compose them in parallel.
// The LeaderRobot and FollowerRobot communicate via channels.
// The Environment generates non-deterministic external events.

Leader = LeaderRobot();
Follower = FollowerRobot();
Env = Environment();

system Leader, Follower, Env;
